#include<bits/stdc++.h>
#define ull unsigned long long
#define ll long long
#define pb push_back
#define pii pair<int,int>
#define vi vector<int>
using namespace std;
const int N =100005;
int n,m,x; 
int a[N],f[N];
unordered_map<int, int> lst;
int main() {
    cin >> n >> m >> x;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        lst[a[i]] = i;
        f[i] = max (f[i - 1], lst[a[i] ^ x]);
    }
    for (int i = 1; i <= m; i++) {
        int l, r;
        cin >> l >> r;
        if (f[r] < l) {
            cout << "no\n";
        } else {
            cout << "yes\n";
        }
    }
	return 0;
}
